import React, { useState, createContext, useContext, useEffect } from 'react';
import { Screen, Language, PondConfig } from './types';
import BottomNav from './components/BottomNav';
import Dashboard from './screens/Dashboard';
import DiseaseDetection from './screens/DiseaseDetection';
import Marketplace from './screens/Marketplace';
import ColdStorageScreen from './screens/ColdStorage';
import Analytics from './screens/Analytics';
import Profile from './screens/Profile';
import Login from './screens/Login';
import LanguageSelection from './screens/LanguageSelection';
import AIAssistant from './components/AIAssistant';
import TutorialOverlay from './components/TutorialOverlay';
import { COLORS, TRANSLATIONS } from './constants';

interface UserData {
  name: string;
  phone: string;
  email: string;
  type: 'google' | 'standard';
}

interface LanguageContextType {
  lang: Language;
  setLang: (l: Language) => void;
  t: (key: string) => string;
}

interface ThemeContextType {
  theme: 'light' | 'dark';
  toggleTheme: () => void;
}

interface UserContextType {
  user: UserData | null;
  setUser: (u: UserData | null) => void;
}

interface NavigationContextType {
  currentScreen: Screen;
  navigate: (s: Screen) => void;
}

interface PondContextType {
  pond: PondConfig;
  setPond: React.Dispatch<React.SetStateAction<PondConfig>>;
}

const LanguageContext = createContext<LanguageContextType | undefined>(undefined);
const ThemeContext = createContext<ThemeContextType | undefined>(undefined);
const UserContext = createContext<UserContextType | undefined>(undefined);
const NavigationContext = createContext<NavigationContextType | undefined>(undefined);
const PondContext = createContext<PondContextType | undefined>(undefined);

export const useLanguage = () => {
  const context = useContext(LanguageContext);
  if (!context) throw new Error("useLanguage must be used within LanguageProvider");
  return context;
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) throw new Error("useTheme must be used within ThemeProvider");
  return context;
};

export const useUser = () => {
  const context = useContext(UserContext);
  if (!context) throw new Error("useUser must be used within UserProvider");
  return context;
};

export const useNavigation = () => {
  const context = useContext(NavigationContext);
  if (!context) throw new Error("useNavigation must be used within NavigationProvider");
  return context;
};

export const usePond = () => {
  const context = useContext(PondContext);
  if (!context) throw new Error("usePond must be used within PondProvider");
  return context;
};

const App: React.FC = () => {
  const [user, setUser] = useState<UserData | null>(null);
  const [isLanguageSelected, setIsLanguageSelected] = useState(false);
  const [showTutorial, setShowTutorial] = useState(false);
  const [currentScreen, setCurrentScreen] = useState<Screen>(Screen.DASHBOARD);
  const [lang, setLang] = useState<Language>(Language.ENGLISH);
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    return (localStorage.getItem('finguard-theme') as 'light' | 'dark') || 'light';
  });

  const [pond, setPond] = useState<PondConfig>({
    id: 'POND-ALPHA-01',
    name: 'Pond Alpha',
    tankSize: '5,000 Liters',
    fishCount: 1200,
    fishType: 'Rohu & Catla',
    metrics: {
      temp: '28.5',
      ph: '7.8',
      oxygen: '6.2',
      ammonia: '0.02'
    },
    healthScore: 84
  });

  useEffect(() => {
    localStorage.setItem('finguard-theme', theme);
  }, [theme]);

  const t = (key: string) => {
    return TRANSLATIONS[lang]?.[key] || TRANSLATIONS.en[key] || key;
  };

  const toggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

  const handleLanguageSelect = (selectedLang: Language) => {
    setLang(selectedLang);
    setIsLanguageSelected(true);
    setShowTutorial(true); // Trigger tutorial after language selection
  };

  const renderScreen = () => {
    switch (currentScreen) {
      case Screen.DASHBOARD: return <Dashboard />;
      case Screen.DISEASE: return <DiseaseDetection />;
      case Screen.MARKETPLACE: return <Marketplace />;
      case Screen.COLD_STORAGE: return <ColdStorageScreen />;
      case Screen.ANALYTICS: return <Analytics />;
      case Screen.PROFILE: return <Profile />;
      default: return <Dashboard />;
    }
  };

  if (!user) {
    return (
      <UserContext.Provider value={{ user, setUser }}>
        <Login onLogin={() => {}} />
      </UserContext.Provider>
    );
  }

  if (!isLanguageSelected) {
    return (
      <LanguageContext.Provider value={{ lang, setLang, t }}>
        <LanguageSelection onSelect={handleLanguageSelect} />
      </LanguageContext.Provider>
    );
  }

  return (
    <UserContext.Provider value={{ user, setUser }}>
      <ThemeContext.Provider value={{ theme, toggleTheme }}>
        <LanguageContext.Provider value={{ lang, setLang, t }}>
          <NavigationContext.Provider value={{ currentScreen, navigate: setCurrentScreen }}>
            <PondContext.Provider value={{ pond, setPond }}>
              <div 
                className={`min-h-screen max-w-lg mx-auto flex flex-col relative animate-in fade-in duration-1000 shadow-2xl transition-colors duration-500 ${theme === 'dark' ? 'bg-[#0F172A] dark' : 'bg-[#F5F8FA]'}`}
                style={{ color: theme === 'dark' ? '#F1F5F9' : COLORS.darkText }}
              >
                <main className="flex-1 overflow-y-auto overflow-x-hidden no-scrollbar">
                  {renderScreen()}
                </main>

                {showTutorial && <TutorialOverlay onComplete={() => setShowTutorial(false)} />}

                <AIAssistant />

                <BottomNav 
                  currentScreen={currentScreen} 
                  onScreenChange={setCurrentScreen} 
                />
              </div>
            </PondContext.Provider>
          </NavigationContext.Provider>
        </LanguageContext.Provider>
      </ThemeContext.Provider>
    </UserContext.Provider>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { PondConfig, Screen } from "../types";

const ELEVEN_LABS_API_KEY = 'sk_d4ed41a77c069da3da3289e901897b314d382f6ef1845c8d';
const VOICE_ID = 'Z1mjfzamgmGKi9c390rc';

export interface AIResponse {
  text: string;
  navigate?: Screen;
}

export const getGeminiAnalysis = async (query: string, pond: PondConfig): Promise<AIResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const systemInstruction = `
    You are FinGuard AI, an expert aquaculture navigator and consultant. 
    CURRENT POND DATA:
    - Name: ${pond.name}, Health: ${pond.healthScore}/100, Fish: ${pond.fishCount}.

    NAVIGATION COMMANDS:
    If the user wants to go to a specific section, map it to these Screen IDs:
    - "DASHBOARD": Home, metrics, main screen
    - "MARKETPLACE": Market, buy feed, shopping, bulk purchase
    - "DISEASE": Detect disease, scan fish, camera diagnostic
    - "COLD_STORAGE": Storage, cold chain, freezing facilities
    - "ANALYTICS": Data, charts, growth trends, yield forecast
    - "PROFILE": Settings, language, my farm, logout

    RESPONSE FORMAT:
    Always respond in JSON format:
    {
      "text": "Your helpful verbal response here",
      "navigate": "SCREEN_ID_OR_NULL"
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: query,
      config: {
        systemInstruction,
        temperature: 0.7,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            text: { type: Type.STRING },
            navigate: { type: Type.STRING, nullable: true }
          },
          required: ["text"]
        }
      },
    });

    const json = JSON.parse(response.text || "{}");
    return {
      text: json.text || "I'm here to help.",
      navigate: json.navigate as Screen || undefined
    };
  } catch (error) {
    console.error("Gemini Error:", error);
    return { text: "The AI system is temporarily unavailable." };
  }
};

export const speakWithElevenLabs = async (text: string): Promise<HTMLAudioElement | null> => {
  try {
    const response = await fetch(`https://api.elevenlabs.io/v1/text-to-speech/${VOICE_ID}`, {
      method: 'POST',
      headers: {
        'xi-api-key': ELEVEN_LABS_API_KEY,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        text,
        model_id: "eleven_multilingual_v2",
        voice_settings: {
          stability: 0.5,
          similarity_boost: 0.75,
        }
      }),
    });

    if (!response.ok) throw new Error("ElevenLabs API failure");

    const blob = await response.blob();
    const url = URL.createObjectURL(blob);
    return new Audio(url);
  } catch (error) {
    console.error("ElevenLabs Error:", error);
    return null;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Mic, X, MessageSquare, Send, Sparkles, Volume2, Loader2, Waves, Command } from 'lucide-react';
import { usePond, useTheme, useLanguage, useNavigation } from '../App';
import { getGeminiAnalysis, speakWithElevenLabs } from '../services/aiAssistantService';

const AIAssistant: React.FC = () => {
  const { pond } = usePond();
  const { theme } = useTheme();
  const { lang } = useLanguage();
  const { navigate } = useNavigation();

  const [isOpen, setIsOpen] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [query, setQuery] = useState('');
  const [transcript, setTranscript] = useState<{role: 'user' | 'ai', text: string}[]>([]);

  const recognitionRef = useRef<any>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    if (typeof window !== 'undefined' && ('SpeechRecognition' in window || 'webkitSpeechRecognition' in window)) {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.interimResults = false;
      recognitionRef.current.lang = lang === 'en' ? 'en-US' : 'hi-IN';

      recognitionRef.current.onresult = (event: any) => {
        const text = event.results[0][0].transcript;
        handleSendMessage(text);
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
      };
    }
  }, [lang]);

  const handleSendMessage = async (textToUse?: string) => {
    const message = textToUse || query;
    if (!message.trim()) return;

    setQuery('');
    setTranscript(prev => [...prev, { role: 'user', text: message }]);
    setIsProcessing(true);

    try {
      const aiResponse = await getGeminiAnalysis(message, pond);
      setTranscript(prev => [...prev, { role: 'ai', text: aiResponse.text }]);

      // Execute Navigation if suggested by AI
      if (aiResponse.navigate) {
        navigate(aiResponse.navigate);
      }

      // Stop previous audio if any
      if (audioRef.current) {
        audioRef.current.pause();
      }

      setIsSpeaking(true);
      const audio = await speakWithElevenLabs(aiResponse.text);
      if (audio) {
        audioRef.current = audio;
        audio.onended = () => setIsSpeaking(false);
        audio.play();
      } else {
        setIsSpeaking(false);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setIsProcessing(false);
    }
  };

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      setIsListening(true);
      recognitionRef.current?.start();
    }
  };

  if (!isOpen) {
    return (
      <button 
        onClick={() => setIsOpen(true)}
        className="fixed bottom-28 right-6 z-[70] w-14 h-14 bg-blue-600 rounded-full flex items-center justify-center text-white shadow-2xl shadow-blue-500/30 active:scale-90 transition-all group overflow-hidden"
      >
        <div className="absolute inset-0 bg-white/20 scale-0 group-hover:scale-100 transition-transform rounded-full"></div>
        <Sparkles size={24} className="relative z-10" />
      </button>
    );
  }

  return (
    <div className="fixed inset-0 z-[100] flex flex-col p-6 animate-in fade-in duration-300">
      <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md" onClick={() => setIsOpen(false)} />

      <div className={`mt-auto w-full max-w-sm mx-auto rounded-[2.5rem] p-6 shadow-2xl relative animate-in slide-in-from-bottom-20 duration-500 border ${theme === 'dark' ? 'bg-slate-900 border-white/10' : 'bg-white border-slate-100'}`}>
        <div className="flex justify-between items-center mb-6">
          <div className="flex items-center space-x-2">
            <div className="p-2 bg-blue-50 dark:bg-blue-500/10 rounded-xl text-blue-500">
              <Sparkles size={18} />
            </div>
            <div>
              <h3 className={`text-sm font-black uppercase tracking-widest ${theme === 'dark' ? 'text-white' : 'text-slate-800'}`}>FinGuard AI</h3>
              {isSpeaking && <p className="text-[10px] text-emerald-500 font-bold uppercase animate-pulse">AI is Speaking...</p>}
            </div>
          </div>
          <button onClick={() => setIsOpen(false)} className="text-slate-400 p-2">
            <X size={20} />
          </button>
        </div>

        <div className="max-h-[300px] overflow-y-auto mb-6 space-y-4 no-scrollbar">
          {transcript.length === 0 ? (
            <div className="text-center py-8 space-y-4">
              <div className="relative mx-auto w-24 h-24 flex items-center justify-center">
                <div className="absolute inset-0 bg-blue-500/10 rounded-full animate-ping"></div>
                <div className="absolute inset-4 bg-blue-500/20 rounded-full animate-pulse"></div>
                <Volume2 className="text-blue-500 relative z-10" size={40} />
              </div>
              <div className="space-y-1">
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Try saying...</p>
                <p className={`text-sm font-medium italic ${theme === 'dark' ? 'text-slate-300' : 'text-slate-600'}`}>"Go to the marketplace"</p>
              </div>
            </div>
          ) : (
            transcript.map((msg, i) => (
              <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-4 rounded-3xl text-sm shadow-sm leading-relaxed ${
                  msg.role === 'user' 
                    ? 'bg-blue-600 text-white rounded-tr-none' 
                    : (theme === 'dark' ? 'bg-slate-800 text-slate-200 rounded-tl-none border border-white/5' : 'bg-slate-50 text-slate-700 rounded-tl-none border border-slate-100')
                }`}>
                  {msg.text}
                </div>
              </div>
            ))
          )}
          {isProcessing && (
            <div className="flex justify-start">
              <div className={`p-4 rounded-3xl rounded-tl-none flex items-center space-x-2 ${theme === 'dark' ? 'bg-slate-800' : 'bg-slate-50'}`}>
                <Loader2 size={16} className="animate-spin text-blue-500" />
                <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Thinking...</span>
              </div>
            </div>
          )}
        </div>

        {isSpeaking && (
          <div className="flex justify-center mb-6 h-12">
            <div className="flex items-center space-x-1.5 h-full">
              {[1, 2, 3, 4, 5, 6, 7, 8].map(i => (
                <div 
                  key={i} 
                  className="w-1.5 bg-blue-500 rounded-full animate-wave" 
                  style={{ 
                    height: `${Math.random() * 80 + 20}%`,
                    animationDelay: `${i * 0.1}s`
                  }} 
                />
              ))}
            </div>
          </div>
        )}

        <div className="flex items-center space-x-2">
          <button 
            onClick={toggleListening}
            className={`w-14 h-14 rounded-2xl flex items-center justify-center transition-all shadow-lg ${
              isListening 
                ? 'bg-red-500 text-white animate-pulse' 
                : (theme === 'dark' ? 'bg-slate-800 text-slate-400' : 'bg-slate-100 text-slate-500')
            }`}
          >
            <Mic size={24} />
          </button>
          <div className="flex-1 relative">
            <input 
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
              placeholder="Command or Ask..."
              className={`w-full py-4 px-6 rounded-2xl text-sm outline-none transition-all border ${
                theme === 'dark' ? 'bg-slate-800 border-white/5 text-white focus:border-blue-500/50' : 'bg-slate-50 border-slate-100 text-slate-800 focus:border-blue-500/50'
              }`}
            />
            <button 
              onClick={() => handleSendMessage()}
              disabled={isProcessing || !query.trim()}
              className="absolute right-2 top-1/2 -translate-y-1/2 p-2 text-blue-500 disabled:opacity-30"
            >
              <Send size={18} />
            </button>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes wave {
          0%, 100% { transform: scaleY(0.5); }
          50% { transform: scaleY(2); }
        }
        .animate-wave {
          animation: wave 0.8s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
};

export default AIAssistant;

import React, { useState, useEffect, useRef } from 'react';
import { X, Sparkles, ChevronRight, Play, Volume2, ShieldCheck, Waves } from 'lucide-react';
