/**
 * Uses Google Search grounding to find the top 5 products.
 */
export const searchAquacultureProducts = async (query: string): Promise<{ products: SearchProductResult[]; sources: any[] }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Find the top 5 best-rated ${query} specifically for aquaculture in the Indian market. Include estimated price and a short reason to buy.`,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  const lines = response.text.split('\n').filter(l => l.trim().length > 0);
  const products: SearchProductResult[] = [];

  let currentProduct: Partial<SearchProductResult> = {};
  for(const line of lines) {
    if (products.length >= 5) break;
    if (line.match(/^\d\./) || line.startsWith('- **')) {
      if (currentProduct.title) products.push(currentProduct as SearchProductResult);
      currentProduct = {
        title: line.replace(/^\d\.\s*/, '').replace(/\*\*/g, '').split(':')[0].trim(),
        description: line.includes(':') ? line.split(':')[1].trim() : "Highly recommended product found via Google Search.",
        sourceUrl: groundingChunks[products.length]?.web?.uri || "https://google.com/search?q=" + encodeURIComponent(query),
        sourceTitle: groundingChunks[products.length]?.web?.title || "Search Result"
      };
    }
  }
  if (currentProduct.title && products.length < 5) products.push(currentProduct as SearchProductResult);

  return { 
    products: products.length > 0 ? products : [], 
    sources: groundingChunks 
  };
};

/**
