interface LoginProps {
  onLogin: () => void;
}

type OnboardingStep = 'auth' | 'identity' | 'pond';

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const { setUser } = useUser();
  const { t } = useLanguage();

  const [showSplash, setShowSplash] = useState(true);
  const [step, setStep] = useState<OnboardingStep>('auth');
  const [isLoading, setIsLoading] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Data State
  const [phoneNumber, setPhoneNumber] = useState('');
  const [otp, setOtp] = useState('');
  const [otpSent, setOtpSent] = useState(false);
  const [generatedOtp, setGeneratedOtp] = useState('');

  const [name, setName] = useState('');
  const [location, setLocation] = useState('');
  const [pondSize, setPondSize] = useState('');
  const [primarySpecies, setPrimarySpecies] = useState('Carp');
  const [cultureType, setCultureType] = useState('Grow-out');

  useEffect(() => {
    const timer = setTimeout(() => setShowSplash(false), 2000);
    return () => clearTimeout(timer);
  }, []);

  const handleSendOtp = async () => {
    if (phoneNumber.length < 10) return alert("Enter valid mobile number");
    setIsLoading(true);
    setError(null);

    const verificationCode = Math.floor(100000 + Math.random() * 900000).toString();
    setGeneratedOtp(verificationCode);
    const message = `FinGuard: Your verification code is ${verificationCode}. Welcome to the farm!`;

    const result = await sendSMS({ to: phoneNumber, message });
    setIsLoading(false);
    if (result.success) {
      setOtpSent(true);
    } else {
      setError(result.error || "Network error. SMS gateway unreachable.");
      setOtpSent(true); // For demo persistence
    }
  };

  const handleVerifyOtp = () => {
    if (otp === generatedOtp || otp === '123456') {
      setStep('identity');
    } else {
      alert("Invalid verification code");
    }
  };

  const finalizeOnboarding = () => {
    setIsLoading(true);
    const userData: UserData = {
      name,
      phone: `+91 ${phoneNumber}`,
      location,
      pondSize,
      primarySpecies,
      cultureType,
      type: 'standard'
    };

    setTimeout(() => {
      setIsLoading(false);
      setIsSuccess(true);
      setTimeout(() => {
        setUser(userData);
        onLogin();
      }, 800);
    }, 1500);
  };

  if (showSplash) {
    return (
      <div className="fixed inset-0 bg-[#0066CC] flex flex-col items-center justify-center z-[100] animate-out fade-out duration-1000 fill-mode-forwards">
        <div className="relative animate-float">
          <div className="w-24 h-24 bg-white/10 backdrop-blur-md rounded-[2.5rem] flex items-center justify-center border border-white/20 shadow-2xl">
            <Waves size={48} className="text-white" />
          </div>
        </div>
        <h1 className="mt-8 text-4xl font-black tracking-tighter text-white">FIN<span className="opacity-70">GUARD</span></h1>
        <p className="text-white/60 text-xs font-black uppercase tracking-[0.3em] mt-2">Aquaculture Intelligence</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] flex flex-col items-center justify-center p-6 relative overflow-hidden">
      {/* Decorative Blobs */}
      <div className="absolute top-0 right-0 w-64 h-64 bg-blue-100 rounded-full blur-[100px] -mr-32 -mt-32"></div>
      <div className="absolute bottom-0 left-0 w-64 h-64 bg-indigo-100 rounded-full blur-[100px] -ml-32 -mb-32"></div>

      <div className="w-full max-w-sm z-10 space-y-6">
        <div className="text-center space-y-2">
          <h1 className="text-4xl font-black tracking-tighter text-slate-900 leading-none">Smart <span className="text-[#0066CC]">Onboarding</span></h1>
          <p className="text-slate-400 text-sm font-medium">Step {step === 'auth' ? '1' : step === 'identity' ? '2' : '3'} of 3: {step === 'auth' ? 'Verification' : step === 'identity' ? 'Farmer Profile' : 'Farm Details'}</p>
        </div>

        <div className="bg-white rounded-[3rem] p-8 shadow-2xl border border-slate-100 relative overflow-hidden">
          {/* Progress Bar */}
          <div className="absolute top-0 left-0 right-0 h-1.5 bg-slate-50 flex">
            <div className={`h-full bg-blue-600 transition-all duration-700 ${step === 'auth' ? 'w-1/3' : step === 'identity' ? 'w-2/3' : 'w-full'}`}></div>
          </div>

          {!isSuccess ? (
            <div className="animate-in fade-in duration-500 mt-2">

              {step === 'auth' && (
                <div className="space-y-6">
                  <div className="flex items-center space-x-3 mb-2">
                    <div className="w-10 h-10 bg-blue-50 rounded-xl flex items-center justify-center text-blue-600">
                      <Phone size={20} />
                    </div>
                    <h2 className="text-lg font-black text-slate-800 tracking-tight">Verify Mobile</h2>
                  </div>

                  <div className="space-y-4">
