interface LoginProps {
  onLogin: () => void;
}

type OnboardingStep = 'auth' | 'identity' | 'pond';

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const { setUser } = useUser();

  const [step, setStep] = useState<OnboardingStep>('auth');
  const [isLoading, setIsLoading] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Data State
  const [phoneNumber, setPhoneNumber] = useState('');
  const [otp, setOtp] = useState('');
  const [otpSent, setOtpSent] = useState(false);

  const [name, setName] = useState('');
  const [location, setLocation] = useState('');
  const [pondSize, setPondSize] = useState('');
  const [primarySpecies, setPrimarySpecies] = useState('Carp');
  const [cultureType, setCultureType] = useState('Grow-out');

  const handleSendOtp = () => {
    if (phoneNumber.length < 10) return alert("Enter valid mobile number");
    setIsLoading(true);
    setTimeout(() => {
      setIsLoading(false);
      setOtpSent(true);
      setError(null);
    }, 800);
  };

  const handleVerifyOtp = () => {
    // Dummy verification: Any 6 digits or specific demo code
    if (otp.length === 6) {
      setStep('identity');
    } else {
      setError("Please enter a valid 6-digit code for demo.");
    }
  };

  const finalizeOnboarding = () => {
    setIsLoading(true);
    const userData: UserData = {
      name,
      phone: `+91 ${phoneNumber}`,
      location,
      pondSize,
      primarySpecies,
      cultureType,
      type: 'standard'
    };

    setTimeout(() => {
      setIsLoading(false);
      setIsSuccess(true);
      setTimeout(() => {
        setUser(userData);
        onLogin();
      }, 800);
    }, 1500);
