import React, { useState, useEffect } from 'react';
import { 
  Bell, Thermometer, Droplets, Wind, AlertTriangle, ShieldCheck, 
  X, Check, Activity, Send, Smartphone, Loader2, CloudSun, Sun, Gauge, MapPin, Sparkles, MessageSquare, Zap, Flame, Droplet, ExternalLink
} from 'lucide-react';
import { useLanguage, useTheme, usePond } from '../App';
import { broadcastSMS, draftPondReportSMS, triggerNativeSMS } from '../services/smsService';
import { getHighAccuracyLocation } from '../services/locationService';
import { fetchWeatherByCoords, WeatherData } from '../services/weatherService';
import { getWaterQualityCrisisAdvice, SearchProductResult } from '../services/geminiService';

const Dashboard: React.FC = () => {
  const { lang } = useLanguage();
  const { theme } = useTheme();
  const { pond, setPond } = usePond();

  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncError, setSyncError] = useState<string | null>(null);

  // AI Crisis States
  const [isGettingAdvice, setIsGettingAdvice] = useState(false);
  const [crisisAdvice, setCrisisAdvice] = useState<string | null>(null);
  const [crisisProducts, setCrisisProducts] = useState<SearchProductResult[]>([]);

  // SMS States
  const [isSmsModalOpen, setIsSmsModalOpen] = useState(false);
  const [isDrafting, setIsDrafting] = useState(false);
  const [smsDraft, setSmsDraft] = useState('');
  const [isSendingSms, setIsSendingSms] = useState(false);
  const [smsSuccess, setSmsSuccess] = useState(false);

  useEffect(() => {
    handleSync();
  }, []);

  const handleSync = async () => {
    setIsSyncing(true);
    setSyncError(null);
    try {
      const loc = await getHighAccuracyLocation();
      const weatherData = await fetchWeatherByCoords(loc.lat, loc.lng);
      setWeather(weatherData);
    } catch (err: any) {
      setSyncError(err.message || "Sync failed");
    } finally {
      setIsSyncing(false);
    }
  };

  const fetchCrisisAdvice = async () => {
    setIsGettingAdvice(true);
    try {
      const issue = pond.healthScore < 20 ? "Ammonia toxicity and Low Oxygen" : "pH imbalance";
      const { advice, products } = await getWaterQualityCrisisAdvice(issue);
      setCrisisAdvice(advice);
      setCrisisProducts(products);
    } catch (err) {
      console.error(err);
    } finally {
      setIsGettingAdvice(false);
    }
  };

  const handleOpenSmsModal = async () => {
    setIsSmsModalOpen(true);
    setIsDrafting(true);
    setSmsSuccess(false);
    try {
      const draft = await draftPondReportSMS(
        pond.name, 
        pond.metrics, 
        pond.healthScore, 
        lang
      );
      setSmsDraft(draft);
    } catch (err) {
      setSmsDraft(`FinGuard Alert: ${pond.name} Health Score is ${pond.healthScore}. All metrics stable.`);
    } finally {
      setIsDrafting(false);
    }
  };

  const handleBroadcast = async () => {
    setIsSendingSms(true);
    const recipients = ['+919876543210', '+919988776655'];
    const success = await broadcastSMS(recipients, smsDraft);
    if (!success) {
      triggerNativeSMS(recipients[0], smsDraft);
    }
    setSmsSuccess(true);
    setIsSendingSms(false);
    setTimeout(() => setIsSmsModalOpen(false), 2000);
  };

  const getHealthConfig = (score: number) => {
    if (score < 20) {
      return { 
        label: 'SEVERE DANGER', 
        status: 'CRITICAL',
        color: 'text-rose-100 bg-[#500724] border-rose-900/50', // Maroon
        gradient: 'from-[#500724] via-[#881337] to-[#500724]',
        icon: <Flame className="animate-pulse" size={24} />
      };
    }
    if (score < 40) {
      return { 
        label: 'DANGER ZONE', 
        status: 'CRITICAL',
        color: 'text-red-100 bg-[#7f1d1d] border-red-900/50', // Dark Red
        gradient: 'from-[#7f1d1d] via-[#b91c1c] to-[#7f1d1d]',
        icon: <AlertTriangle className="animate-bounce" size={24} />
      };
    }
    if (score < 60) {
      return { 
        label: 'WARNING STATE', 
        status: 'MODERATE',
        color: 'text-orange-100 bg-orange-600 border-orange-700/50', // Orange
        gradient: 'from-orange-600 via-orange-500 to-orange-600',
        icon: <Activity size={24} />
      };
    }
    return { 
      label: 'EXCELLENT', 
      status: 'OPTIMAL',
      color: 'text-emerald-100 bg-emerald-600 border-emerald-700/50', 
      gradient: 'from-emerald-600 via-teal-500 to-emerald-600',
      icon: <ShieldCheck size={24} />
    };
  };

  const health = getHealthConfig(pond.healthScore);

  return (
    <div className={`pb-32 relative min-h-screen transition-all duration-700 ${theme === 'dark' ? 'bg-[#020617]' : 'bg-[#f0f4f8]'}`}>
      <div className={`absolute top-0 left-0 right-0 h-96 opacity-20 blur-[120px] pointer-events-none transition-all duration-1000 bg-gradient-to-b ${health.gradient}`}></div>

      {/* SMS Modal Overlay */}
      {isSmsModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 animate-in fade-in duration-300">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md" onClick={() => setIsSmsModalOpen(false)} />
          <div className={`w-full max-w-sm rounded-[2.5rem] p-8 shadow-2xl relative animate-in zoom-in-95 duration-300 border ${theme === 'dark' ? 'bg-slate-900 border-white/10' : 'bg-white border-slate-100'}`}>
            <div className="flex justify-between items-center mb-6">
              <div className="flex items-center space-x-2">
                <div className="p-2 bg-indigo-50 dark:bg-indigo-500/10 rounded-xl text-indigo-500">
                  <MessageSquare size={18} />
                </div>
                <h3 className={`text-sm font-black uppercase tracking-widest ${theme === 'dark' ? 'text-white' : 'text-slate-800'}`}>AI Report Draft</h3>
              </div>
