/**
 * Finds solutions for hazardous water parameters.
 */
export const getWaterQualityCrisisAdvice = async (issue: string): Promise<{ advice: string; products: SearchProductResult[] }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `My fish pond has a dangerous ${issue}. Suggest immediate corrective actions and find top 3 products in India (like conditioners or buffers) that can fix this.`,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  const products: SearchProductResult[] = [];

  // Extract products from response text (simplified extraction)
  const lines = (response.text || "").split('\n');
  let pCount = 0;
  for(const line of lines) {
    if (pCount >= 3) break;
    if (line.match(/^\d\./) || line.startsWith('- **')) {
      products.push({
        title: line.replace(/^\d\.\s*/, '').replace(/\*\*/g, '').split(':')[0].trim(),
        description: line.includes(':') ? line.split(':')[1].trim() : "Urgent correction tool.",
        sourceUrl: groundingChunks[pCount]?.web?.uri || "https://google.com",
        sourceTitle: groundingChunks[pCount]?.web?.title || "Verified Advice"
