  };
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Bell, Thermometer, Droplets, Wind, AlertTriangle, ShieldCheck, 
  X, Check, Activity, Send, Smartphone, Loader2, CloudSun, Sun, Gauge, MapPin, Sparkles, MessageSquare, Zap, Flame, Droplet, ExternalLink, Settings2, RefreshCcw, Mail, History, Utensils
} from 'lucide-react';
import { useLanguage, useTheme, usePond, useUser } from '../App';
import { broadcastSMS, draftPondReportSMS, triggerNativeSMS } from '../services/smsService';
import { getHighAccuracyLocation } from '../services/locationService';
import { fetchWeatherByCoords, WeatherData } from '../services/weatherService';
import { getWaterQualityCrisisAdvice, SearchProductResult } from '../services/geminiService';

const THRESHOLDS = {
  temp: { min: 18, max: 32 },
  oxygen: { min: 4.0, max: 12 },
  ph: { min: 6.5, max: 8.8 },
  ammonia: { min: 0, max: 0.08 }
};

interface AlertLog {
  timestamp: string;
  parameter: string;
  value: number;
  type: 'CRITICAL' | 'WARNING';
}

const Dashboard: React.FC = () => {
  const { lang } = useLanguage();
  const { theme } = useTheme();
  const { pond, setPond } = usePond();
  const { user } = useUser();

  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncError, setSyncError] = useState<string | null>(null);

  // AI Crisis States
  const [isGettingAdvice, setIsGettingAdvice] = useState(false);
  const [crisisAdvice, setCrisisAdvice] = useState<string | null>(null);
  const [crisisProducts, setCrisisProducts] = useState<SearchProductResult[]>([]);

  // SMS/Alarm States
  const [isSmsModalOpen, setIsSmsModalOpen] = useState(false);
  const [isDrafting, setIsDrafting] = useState(false);
  const [smsDraft, setSmsDraft] = useState('');
  const [isSendingSms, setIsSendingSms] = useState(false);
  const [smsSuccess, setSmsSuccess] = useState(false);
  const [isAlarmActive, setIsAlarmActive] = useState(false);
  const [lastNotifiedTime, setLastNotifiedTime] = useState(0);

  // New Utility States
  const [alertHistory, setAlertHistory] = useState<AlertLog[]>([]);
  const [isAlertsHistoryOpen, setIsAlertsHistoryOpen] = useState(false);
  const [isFeedingActive, setIsFeedingActive] = useState(false);
  const [showFeedSuccess, setShowFeedSuccess] = useState(false);

  // Simulation State
  const [showSimPanel, setShowSimPanel] = useState(false);

  // Determine if any parameter is breached
  const breaches = useMemo(() => {
    return {
      temp: pond.metrics.temp < THRESHOLDS.temp.min || pond.metrics.temp > THRESHOLDS.temp.max,
      oxygen: pond.metrics.oxygen < THRESHOLDS.oxygen.min,
      ph: pond.metrics.ph < THRESHOLDS.ph.min || pond.metrics.ph > THRESHOLDS.ph.max,
      ammonia: pond.metrics.ammonia > THRESHOLDS.ammonia.max
    };
  }, [pond.metrics]);

  const hasAnyBreach = Object.values(breaches).some(b => b);

  useEffect(() => {
    handleSync();
  }, []);

  // Alarm Auto-Trigger & History Logic
  useEffect(() => {
    if (hasAnyBreach) {
      // Add to history if new breach detected
      Object.entries(breaches).forEach(([key, breached]) => {
        if (breached) {
          const paramName = key.charAt(0).toUpperCase() + key.slice(1);
          const val = (pond.metrics as any)[key];

          // Only add if not recently added (debounce history)
          setAlertHistory(prev => {
            const lastAlert = prev[0];
            const isSameAsLast = lastAlert && lastAlert.parameter === paramName && Math.abs(lastAlert.value - val) < 0.1;
            if (isSameAsLast) return prev;

            return [{
              timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
              parameter: paramName,
              value: val,
              type: 'CRITICAL'
            }, ...prev].slice(0, 10); // Keep last 10
          });
        }
      });

      if (!isAlarmActive) {
        setIsAlarmActive(true);
        const now = Date.now();
        if (now - lastNotifiedTime > 300000) {
          handleAutoEmergencyAlert();
          setLastNotifiedTime(now);
        }
      }
    } else if (!hasAnyBreach && isAlarmActive) {
      setIsAlarmActive(false);
    }
  }, [hasAnyBreach, pond.metrics]);

  const handleAutoEmergencyAlert = async () => {
    const alertMsg = `CRITICAL ALERT: ${pond.name} parameters breached safe levels! Temp: ${pond.metrics.temp}, Oxygen: ${pond.metrics.oxygen}. Please check FinGuard App immediately.`;
    const recipients = [user?.phone || '+919876543210'];
    await broadcastSMS(recipients, alertMsg);
    console.log(`[EMAIL SYSTEM] Alert sent to ${user?.name || 'Farmer'}@finguard.ai`);
  };

  const handleSync = async () => {
    setIsSyncing(true);
    setSyncError(null);
    try {
      const loc = await getHighAccuracyLocation();
      const weatherData = await fetchWeatherByCoords(loc.lat, loc.lng);
      setWeather(weatherData);
    } catch (err: any) {
      setSyncError(err.message || "Sync failed");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleQuickFeed = () => {
    setIsFeedingActive(true);
    // Simulate feeding delay
    setTimeout(() => {
      setIsFeedingActive(false);
      setShowFeedSuccess(true);
      // Feeding slightly improves health score if score was dipped
      setPond(prev => ({
        ...prev,
        healthScore: Math.min(100, prev.healthScore + 2)
      }));
      setTimeout(() => setShowFeedSuccess(false), 3000);
    }, 2000);
  };

  const fetchCrisisAdvice = async () => {
    setIsGettingAdvice(true);
    try {
      const issue = hasAnyBreach ? "Multiple parameter breaches including low oxygen" : "Optimization needed";
      const { advice, products } = await getWaterQualityCrisisAdvice(issue);
      setCrisisAdvice(advice);
      setCrisisProducts(products);
    } catch (err) {
      console.error(err);
    } finally {
      setIsGettingAdvice(false);
    }
  };

  const handleOpenSmsModal = async () => {
    setIsSmsModalOpen(true);
    setIsDrafting(true);
    setSmsSuccess(false);
    try {
      const draft = await draftPondReportSMS(
        pond.name, 
        { 
          temp: pond.metrics.temp.toString(), 
          ph: pond.metrics.ph.toString(), 
          oxygen: pond.metrics.oxygen.toString(), 
          ammonia: pond.metrics.ammonia.toString() 
        }, 
        pond.healthScore, 
        lang
      );
      setSmsDraft(draft);
    } catch (err) {
      setSmsDraft(`FinGuard Alert: ${pond.name} Health Score is ${pond.healthScore}. All metrics stable.`);
    } finally {
      setIsDrafting(false);
    }
  };

  const handleBroadcast = async () => {
    setIsSendingSms(true);
    const recipients = [user?.phone || '+919876543210', '+919988776655'];
    const success = await broadcastSMS(recipients, smsDraft);
    if (!success) {
      triggerNativeSMS(recipients[0], smsDraft);
    }
    setSmsSuccess(true);
    setIsSendingSms(false);
    setTimeout(() => setIsSmsModalOpen(false), 2000);
  };

  const getHealthConfig = (score: number) => {
    if (hasAnyBreach) {
      return { 
        label: 'BREACH DETECTED', 
        status: 'CRITICAL',
        color: 'text-rose-100 bg-[#500724] border-rose-900/50',
        gradient: 'from-[#500724] via-rose-600 to-[#500724]',
        icon: <Flame className="animate-pulse" size={24} />
      };
    }
    if (score < 40) {
      return { 
        label: 'DANGER ZONE', 
        status: 'CRITICAL',
        color: 'text-red-100 bg-[#7f1d1d] border-red-900/50',
        gradient: 'from-[#7f1d1d] via-[#b91c1c] to-[#7f1d1d]',
        icon: <AlertTriangle className="animate-bounce" size={24} />
      };
    }
    if (score < 60) {
      return { 
        label: 'WARNING STATE', 
        status: 'MODERATE',
        color: 'text-orange-100 bg-orange-600 border-orange-700/50',
        gradient: 'from-orange-600 via-orange-500 to-orange-600',
        icon: <Activity size={24} />
      };
    }
    return { 
      label: 'EXCELLENT', 
      status: 'OPTIMAL',
      color: 'text-emerald-100 bg-emerald-600 border-emerald-700/50', 
      gradient: 'from-emerald-600 via-teal-500 to-emerald-600',
      icon: <ShieldCheck size={24} />
    };
  };

  const health = getHealthConfig(pond.healthScore);

  return (
    <div className={`pb-48 relative min-h-screen transition-all duration-700 ${theme === 'dark' ? 'bg-[#020617]' : 'bg-[#f0f4f8]'}`}>
      <div className={`fixed top-0 left-0 right-0 h-96 opacity-20 blur-[120px] pointer-events-none transition-all duration-1000 bg-gradient-to-b ${health.gradient}`}></div>

      {/* Emergency Alarm Banner */}
      {isAlarmActive && (
        <div className="fixed top-0 left-0 right-0 z-[100] bg-rose-600 text-white px-6 py-4 flex items-center justify-between shadow-2xl animate-in slide-in-from-top duration-500">
           <div className="flex items-center space-x-3">
              <div className="p-2 bg-white/20 rounded-xl animate-pulse">
                <AlertTriangle size={20} />
              </div>
              <div className="flex flex-col">
                 <span className="text-[10px] font-black uppercase tracking-widest leading-none mb-1 text-rose-200">Critical Failure</span>
                 <span className="text-sm font-black tracking-tight">System Alarm Active</span>
              </div>
           </div>
           <div className="flex items-center space-x-2">
              <div className="flex items-center space-x-1 bg-white/10 px-3 py-1.5 rounded-full border border-white/10">
                 <Smartphone size={12} className="text-rose-200" />
                 <span className="text-[9px] font-black uppercase tracking-widest">AUTO SMS</span>
              </div>
           </div>
        </div>
      )}

      {/* Quick Action Utilities Modal (Alerts History) */}
      {isAlertsHistoryOpen && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 animate-in fade-in duration-300">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md" onClick={() => setIsAlertsHistoryOpen(false)} />
          <div className={`w-full max-w-sm rounded-[2.5rem] p-8 shadow-2xl relative animate-in zoom-in-95 duration-300 border ${theme === 'dark' ? 'bg-slate-900 border-white/10' : 'bg-white border-slate-100'}`}>
            <div className="flex justify-between items-center mb-6">
               <div className="flex items-center space-x-3">
                  <div className="p-2 bg-orange-500/10 rounded-xl text-orange-500">
                    <History size={20} />
                  </div>
                  <h3 className={`text-sm font-black uppercase tracking-widest ${theme === 'dark' ? 'text-white' : 'text-slate-800'}`}>Breach Log</h3>
               </div>
               <button onClick={() => setIsAlertsHistoryOpen(false)} className="text-slate-400 p-2">
                 <X size={24} />
               </button>
            </div>

            <div className="space-y-3 max-h-[400px] overflow-y-auto no-scrollbar pr-1">
               {alertHistory.length === 0 ? (
                 <div className="py-12 flex flex-col items-center justify-center text-center space-y-3">
                    <ShieldCheck className="text-emerald-500" size={48} />
                    <p className="text-xs font-black text-slate-400 uppercase tracking-widest">No recent breaches</p>
