                    <div className="flex items-center space-x-3">
                       <div className="w-1.5 h-8 bg-rose-500 rounded-full"></div>
                       <div className="flex flex-col">
                          <span className={`text-[11px] font-black ${theme === 'dark' ? 'text-white' : 'text-slate-800'}`}>{alert.parameter} Level High</span>
                          <span className="text-[9px] font-bold text-slate-400 uppercase">{alert.timestamp}</span>
                       </div>
                    </div>
                    <span className="text-xs font-black text-rose-500">{alert.value}</span>
                 </div>
               ))}
            </div>
          </div>
        </div>
      )}

      {/* Feeding Toast Overlay */}
      {(isFeedingActive || showFeedSuccess) && (
        <div className="fixed top-12 left-1/2 -translate-x-1/2 z-[130] w-fit animate-in slide-in-from-top-4 duration-300">
           <div className={`px-6 py-4 rounded-full shadow-2xl flex items-center space-x-3 border-2 ${
             showFeedSuccess ? 'bg-emerald-600 border-emerald-400 text-white' : 'bg-blue-600 border-blue-400 text-white'
           }`}>
              {isFeedingActive ? <Loader2 size={18} className="animate-spin" /> : <Check size={18} strokeWidth={3} />}
              <span className="text-[10px] font-black uppercase tracking-[0.2em] whitespace-nowrap">
                {isFeedingActive ? 'Dispensing High-Protein Feed...' : 'Feeding Logged Successfully'}
              </span>
           </div>
        </div>
