                 <div key={ctrl.key} className="space-y-3">
                    <div className="flex justify-between items-center">
                       <label className={`text-[10px] font-black uppercase tracking-widest ${theme === 'dark' ? 'text-slate-400' : 'text-slate-500'}`}>{ctrl.label}</label>
