                        {(pond.metrics as any)[ctrl.key]} {ctrl.unit}
                       </span>
                    </div>
                    <input 
                      type="range" 
                      min={ctrl.min} 
                      max={ctrl.max} 
                      step={ctrl.step} 
                      value={(pond.metrics as any)[ctrl.key]}
                      onChange={(e) => {
                        const val = parseFloat(e.target.value);
                        setPond(prev => ({
                          ...prev,
                          metrics: { ...prev.metrics, [ctrl.key]: val },
                          healthScore: val > (THRESHOLDS as any)[ctrl.key].max ? prev.healthScore - 10 : prev.healthScore
                        }));
                      }}
                      className="w-full h-2 bg-slate-200 dark:bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-600"
                    />
                 </div>
               ))}

               <div className="pt-4 flex space-x-3">
                  <button 
                    onClick={() => setPond(prev => ({
                      ...prev,
                      metrics: { temp: 28.5, ph: 7.8, oxygen: 6.2, ammonia: 0.02 },
                      healthScore: 84
                    }))}
                    className="flex-1 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center space-x-2"
                  >
                    <RefreshCcw size={14} />
                    <span>Reset Sensors</span>
                  </button>
                  <button 
                    onClick={() => setPond(prev => ({
                      ...prev,
                      metrics: { ...prev.metrics, oxygen: 2.1, temp: 36.5 },
                    }))}
                    className="flex-1 bg-rose-600 text-white py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center space-x-2 shadow-lg shadow-rose-500/30"
                  >
                    <Zap size={14} />
                    <span>Trigger Crisis</span>
                  </button>
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

