// Dashboard.tsx
import React, { useState, useEffect } from 'react';

interface AlertLog {
  timestamp: string;
  parameter: string;
  value: number;
  type: 'CRITICAL' | 'WARNING';
}

interface PondData {
  pondName: string;
  metrics: {
    temp: number;
    ph: number;
    oxygen: number;
    ammonia: number;
  };
  healthScore: number;
}

interface Props {
    pondData: PondData;
    geminiService: any;
    smsService: any;
}


const Dashboard: React.FC<Props> = ({ pondData, geminiService, smsService }) => {
  const [alertHistory, setAlertHistory] = useState<AlertLog[]>([]);

  const { pondName, metrics, healthScore } = pondData;

  useEffect(() => {
    const checkAlerts = () => {
      const paramNames = Object.keys(metrics);
      paramNames.forEach(paramName => {
        const value = metrics[paramName as keyof typeof metrics];
        let val:number;
          if (typeof value === 'number') {
              val = value;
          } else {
              val = parseFloat(value as string);
          }
        let type: 'CRITICAL' | 'WARNING' | undefined = undefined;

        if (paramName === 'temp' && (val > 30 || val < 20)) {
          type = 'WARNING';
        } else if (paramName === 'ph' && (val > 8.5 || val < 6.5)) {
          type = 'CRITICAL';
        } else if (paramName === 'oxygen' && val < 4) {
          type = 'CRITICAL';
        } else if (paramName === 'ammonia' && val > 0.5) {
          type = 'CRITICAL';
        }

        if (type) {
          // Only add if not recently added (debounce history)
          setAlertHistory(prev => {
            const lastAlert = prev[0];
