  const breaches = useMemo(() => {
    return {
      temp: pond.metrics.temp < THRESHOLDS.temp.min || pond.metrics.temp > THRESHOLDS.temp.max,
      oxygen: pond.metrics.oxygen < THRESHOLDS.oxygen.min,
      ph: pond.metrics.ph < THRESHOLDS.ph.min || pond.metrics.ph > THRESHOLDS.ph.max,
      ammonia: pond.metrics.ammonia > THRESHOLDS.ammonia.max
    };
  }, [pond.metrics]);

  const hasAnyBreach = Object.values(breaches).some(b => b);

  useEffect(() => {
    handleSync();
  }, []);

  // Alarm Auto-Trigger & History Logic
  useEffect(() => {
    if (hasAnyBreach) {
      // Add to history if new breach detected
      Object.entries(breaches).forEach(([key, breached]) => {
        if (breached) {
          const paramName = key.charAt(0).toUpperCase() + key.slice(1);
          const val = (pond.metrics as any)[key];

          // Only add if not recently added (debounce history)
          setAlertHistory(prev => {
            const lastAlert = prev[0];
            const isSameAsLast = lastAlert && lastAlert.parameter === paramName && Math.abs(lastAlert.value - val) < 0.1;
            if (isSameAsLast) return prev;

            // Fixed: Explicitly typed the new entry to match AlertLog interface and avoid literal widening issues
            const newEntry: AlertLog = {
              timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
              parameter: paramName,
              value: val,
              type: 'CRITICAL'
            };
            return [newEntry, ...prev].slice(0, 10); // Keep last 10
          });
        }
      });

      if (!isAlarmActive) {
        setIsAlarmActive(true);
        const now = Date.now();
        if (now - lastNotifiedTime > 300000) {
          handleAutoEmergencyAlert();
          setLastNotifiedTime(now);
        }
      }
    } else if (!hasAnyBreach && isAlarmActive) {
      setIsAlarmActive(false);
    }
  }, [hasAnyBreach, pond.metrics]);

  const handleAutoEmergencyAlert = async () => {
    const alertMsg = `CRITICAL ALERT: ${pond.name} parameters breached safe levels! Temp: ${pond.metrics.temp}, Oxygen: ${pond.metrics.oxygen}. Please check FinGuard App immediately.`;
    const recipients = [user?.phone || '+919876543210'];
    await broadcastSMS(recipients, alertMsg);
    console.log(`[EMAIL SYSTEM] Alert sent to ${user?.name || 'Farmer'}@finguard.ai`);
  };

  const handleSync = async () => {
    setIsSyncing(true);
    setSyncError(null);
    try {
      const loc = await getHighAccuracyLocation();
      const weatherData = await fetchWeatherByCoords(loc.lat, loc.lng);
      setWeather(weatherData);
    } catch (err: any) {
      setSyncError(err.message || "Sync failed");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleQuickFeed = () => {
    setIsFeedingActive(true);
