      const issue = hasAnyBreach ? "Multiple parameter breaches including low oxygen" : "Optimization needed";
      const { advice, products } = await getWaterQualityCrisisAdvice(issue);
      setCrisisAdvice(advice);
      setCrisisProducts(products);
    } catch (err) {
      console.error(err);
    } finally {
      setIsGettingAdvice(false);
    }
  };

  const handleOpenSmsModal = async () => {
    setIsSmsModalOpen(true);
    setIsDrafting(true);
    setSmsSuccess(false);
    try {
      const draft = await draftPondReportSMS(
        pond.name, 
        { 
          temp: pond.metrics.temp.toString(), 
          ph: pond.metrics.ph.toString(), 
          oxygen: pond.metrics.oxygen.toString(), 
          ammonia: pond.metrics.ammonia.toString() 
        }, 
        pond.healthScore, 
        lang
      );
      setSmsDraft(draft);
    } catch (err) {
      setSmsDraft(`FinGuard Alert: ${pond.name} Health Score is ${pond.healthScore}. All metrics stable.`);
    } finally {
      setIsDrafting(false);
    }
  };

  const handleBroadcast = async () => {
    setIsSendingSms(true);
    const recipients = [user?.phone || '+919876543210', '+919988776655'];
    const success = await broadcastSMS(recipients, smsDraft);
    if (!success) {
      triggerNativeSMS(recipients[0], smsDraft);
    }
    setSmsSuccess(true);
    setIsSendingSms(false);
    setTimeout(() => setIsSmsModalOpen(false), 2000);
  };

  const getHealthConfig = (score: number) => {
    if (hasAnyBreach) {
      return { 
        label: 'BREACH DETECTED', 
        status: 'CRITICAL',
        color: 'text-rose-100 bg-[#500724] border-rose-900/50',
        gradient: 'from-[#500724] via-rose-600 to-[#500724]',
        icon: <Flame className="animate-pulse" size={24} />
      };
    }
    if (score < 40) {
      return { 
        label: 'DANGER ZONE', 
        status: 'CRITICAL',
        color: 'text-red-100 bg-[#7f1d1d] border-red-900/50',
        gradient: 'from-[#7f1d1d] via-[#b91c1c] to-[#7f1d1d]',
        icon: <AlertTriangle className="animate-bounce" size={24} />
      };
    }
    if (score < 60) {
      return { 
        label: 'WARNING STATE', 
        status: 'MODERATE',
        color: 'text-orange-100 bg-orange-600 border-orange-700/50',
        gradient: 'from-orange-600 via-orange-500 to-orange-600',
        icon: <Activity size={24} />
      };
    }
    return { 
      label: 'EXCELLENT', 
      status: 'OPTIMAL',
      color: 'text-emerald-100 bg-emerald-600 border-emerald-700/50', 
      gradient: 'from-emerald-600 via-teal-500 to-emerald-600',
      icon: <ShieldCheck size={24} />
    };
  };

  const health = getHealthConfig(pond.healthScore);

  return (
    <div className={`pb-48 relative min-h-screen transition-all duration-700 ${theme === 'dark' ? 'bg-[#020617]' : 'bg-[#f0f4f8]'}`}>
      <div className={`fixed top-0 left-0 right-0 h-96 opacity-20 blur-[120px] pointer-events-none transition-all duration-1000 bg-gradient-to-b ${health.gradient}`}></div>

      {/* Emergency Alarm Banner */}
      {isAlarmActive && (
        <div className="fixed top-0 left-0 right-0 z-[100] bg-rose-600 text-white px-6 py-4 flex items-center justify-between shadow-2xl animate-in slide-in-from-top duration-500">
           <div className="flex items-center space-x-3">
              <div className="p-2 bg-white/20 rounded-xl animate-pulse">
                <AlertTriangle size={20} />
              </div>
              <div className="flex flex-col">
                 <span className="text-[10px] font-black uppercase tracking-widest leading-none mb-1 text-rose-200">Critical Failure</span>
                 <span className="text-sm font-black tracking-tight">System Alarm Active</span>
              </div>
           </div>
           <div className="flex items-center space-x-2">
              <div className="flex items-center space-x-1 bg-white/10 px-3 py-1.5 rounded-full border border-white/10">
                 <Smartphone size={12} className="text-rose-200" />
                 <span className="text-[9px] font-black uppercase tracking-widest">AUTO SMS</span>
              </div>
