import { GoogleGenAI, Type } from "@google/genai";
import { PondMetrics, DiseaseAnalysis } from "../types";

export interface SearchProductResult {
  title: string;
  price?: string;
  description: string;
  sourceUrl: string;
  sourceTitle: string;
}

/**
 * Analyzes pond health metrics using reasoning-optimized Gemini 3 Pro.
 */
export const analyzePondHealth = async (metrics: PondMetrics): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `Analyze the following pond water metrics for aquaculture in India. Provide a health score (0-100), detailed feedback, and actionable recommendations.
  Metrics:
  - pH: ${metrics.ph}
  - Temperature: ${metrics.temp}°C
  - Dissolved Oxygen: ${metrics.oxygen} mg/L
  - Ammonia: ${metrics.ammonia} mg/L`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      thinkingConfig: { thinkingBudget: 2000 }
    }
  });

  return response.text || "Analysis failed. Please try again.";
};

/**
 * Detects fish diseases using Gemini 3 Pro Vision with expert pathological instructions.
 */
export const detectFishDisease = async (base64Image: string): Promise<DiseaseAnalysis> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
        { text: "Perform a detailed pathological analysis of the fish in this image. Identify any visible symptoms like white spots, fin rot, cotton-like growths, or hemorrhages. If a disease is detected, name it. If the fish looks healthy, specify 'Healthy'. Provide the result in the requested JSON format." }
      ]
    },
    config: {
      systemInstruction: "You are a Senior Fish Pathologist specializing in aquaculture. Your goal is to provide accurate disease identification for fish farmers. Be specific and clinical. If the image does not show a fish, set confidence to 0 and diseaseId to 'Not a Fish'.",
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          diseaseId: { type: Type.STRING, description: "Common name of the disease, e.g., 'Ich (White Spot)', 'Fin Rot', 'Healthy'" },
          confidence: { type: Type.NUMBER, description: "Confidence level between 0 and 1" },
          treatmentPlan: { type: Type.STRING, description: "Step-by-step treatment instructions" },
          recommendations: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Preventative measures for the pond" }
        },
        required: ["diseaseId", "confidence", "treatmentPlan", "recommendations"]
      }
    }
  });

  const jsonStr = response.text || "{}";
  try {
    const data = JSON.parse(jsonStr);
    // Ensure fallback values if the model returned an incomplete object
    return {
      diseaseId: data.diseaseId || 'Unknown / Inconclusive',
      confidence: data.confidence || 0,
      treatmentPlan: data.treatmentPlan || 'No specific treatment identified. Monitor the pond closely.',
      recommendations: data.recommendations || ['Maintain optimal water parameters.']
    };
  } catch (e) {
    throw new Error("Failed to parse AI diagnosis.");
  }
};

/**
 * Uses Google Search grounding to find the top 5 products.
 */
export const searchAquacultureProducts = async (query: string): Promise<{ products: SearchProductResult[]; sources: any[] }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Find the top 5 best-rated ${query} specifically for aquaculture in the Indian market. Include estimated price and a short reason to buy.`,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  const lines = (response.text || "").split('\n').filter(l => l.trim().length > 0);
  const products: SearchProductResult[] = [];

  let currentProduct: Partial<SearchProductResult> = {};
  for(const line of lines) {
    if (products.length >= 5) break;
    if (line.match(/^\d\./) || line.startsWith('- **')) {
      if (currentProduct.title) products.push(currentProduct as SearchProductResult);
      currentProduct = {
        title: line.replace(/^\d\.\s*/, '').replace(/\*\*/g, '').split(':')[0].trim(),
        description: line.includes(':') ? line.split(':')[1].trim() : "Highly recommended product found via Google Search.",
        sourceUrl: groundingChunks[products.length]?.web?.uri || "https://google.com/search?q=" + encodeURIComponent(query),
        sourceTitle: groundingChunks[products.length]?.web?.title || "Search Result"
      };
    }
  }
  if (currentProduct.title && products.length < 5) products.push(currentProduct as SearchProductResult);

  return { 
    products: products.length > 0 ? products : [], 
    sources: groundingChunks 
  };
};

/**
 * Fetches quick search suggestions based on partial input.
 */
export const getSearchSuggestions = async (partial: string): Promise<string[]> => {
  if (!partial || partial.length < 2) return [];
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Provide 5 short aquaculture search suggestions starting with or related to "${partial}". Return only a JSON array of strings.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: { type: Type.STRING }
      }
    }
  });

  try {
    return JSON.parse(response.text || "[]");
  } catch {
    return [];
  }
};

/**
 * Specifically finds medical treatments for a given fish disease using search grounding.
 */
export const getTreatmentMedicines = async (diseaseName: string): Promise<{ products: SearchProductResult[] }> => {
  if (diseaseName.toLowerCase().includes('healthy')) return { products: [] };

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Find top 3 specific medicines or water conditioners available on Amazon.in, Indiamart, or Moglix that treat ${diseaseName} in aquaculture.`,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  const lines = (response.text || "").split('\n').filter(l => l.trim().length > 0);
  const products: SearchProductResult[] = [];

  let currentProduct: Partial<SearchProductResult> = {};
  for(const line of lines) {
    if (products.length >= 3) break;
    if (line.match(/^\d\./) || line.startsWith('- **')) {
      if (currentProduct.title) products.push(currentProduct as SearchProductResult);
      currentProduct = {
        title: line.replace(/^\d\.\s*/, '').replace(/\*\*/g, '').split(':')[0].trim(),
        description: line.includes(':') ? line.split(':')[1].trim() : "Effective medicine for " + diseaseName,
        sourceUrl: groundingChunks[products.length]?.web?.uri || "https://google.com/search?q=buy+" + encodeURIComponent(line),
        sourceTitle: groundingChunks[products.length]?.web?.title || "Market Result"
      };
    }
  }
  if (currentProduct.title && products.length < 3) products.push(currentProduct as SearchProductResult);

  return { products };
};

