        </div>
      </div>

      {/* Simulation Console */}
      {showSimPanel && (
        <div className="fixed inset-0 z-[120] flex items-end justify-center animate-in fade-in duration-300">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md" onClick={() => setShowSimPanel(false)} />
