              <button onClick={() => setShowSimPanel(false)}><X size={24} className="text-slate-400" /></button>
            </div>
            <div className="space-y-6">
              {Object.keys(pond.metrics).map((key) => (
                <div key={key} className="space-y-2">
                  <div className="flex justify-between text-[10px] font-black uppercase text-slate-400">
                    <span>{key}</span>
                    <span className="text-blue-500">{(pond.metrics as any)[key]}</span>
                  </div>
                  <input 
                    type="range" min="0" max="40" step="0.1" 
