                <button onClick={() => setPond(p => ({ ...p, metrics: { temp: 28, ph: 7.5, oxygen: 6.5, ammonia: 0.01 } }))} className="flex-1 bg-slate-100 dark:bg-slate-800 p-4 rounded-2xl text-[10px] font-black uppercase">Reset</button>
                <button onClick={() => setPond(p => ({ ...p, metrics: { ...p.metrics, oxygen: 1.5 } }))} className="flex-1 bg-rose-600 text-white p-4 rounded-2xl text-[10px] font-black uppercase shadow-lg shadow-rose-500/30">Trigger Crisis</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

