import { 
  Bell, Thermometer, Wind, AlertTriangle, ShieldCheck, 
  X, Check, Activity, Send, Smartphone, Loader2, CloudSun, Sun, Gauge, MapPin, Sparkles, MessageSquare, Zap, Flame, Droplet, ExternalLink, Settings2, RefreshCcw, History
} from 'lucide-react';
