import Login from './screens/Login';
import LanguageSelection from './screens/LanguageSelection';
import SplashScreen from './screens/SplashScreen';
import AIAssistant from './components/AIAssistant';
import TutorialOverlay from './components/TutorialOverlay';
import { COLORS, TRANSLATIONS } from './constants';

interface LanguageContextType {
  lang: Language;
  setLang: (l: Language) => void;
  t: (key: string) => string;
}

interface ThemeContextType {
  theme: 'light' | 'dark';
  toggleTheme: () => void;
}

interface UserContextType {
  user: UserData | null;
  setUser: (u: UserData | null) => void;
}

interface NavigationContextType {
  currentScreen: Screen;
  navigate: (s: Screen) => void;
}

interface PondContextType {
  pond: PondConfig;
  setPond: React.Dispatch<React.SetStateAction<PondConfig>>;
}

const LanguageContext = createContext<LanguageContextType | undefined>(undefined);
const ThemeContext = createContext<ThemeContextType | undefined>(undefined);
const UserContext = createContext<UserContextType | undefined>(undefined);
const NavigationContext = createContext<NavigationContextType | undefined>(undefined);
const PondContext = createContext<PondContextType | undefined>(undefined);

export const useLanguage = () => {
  const context = useContext(LanguageContext);
  if (!context) throw new Error("useLanguage must be used within LanguageProvider");
  return context;
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) throw new Error("useTheme must be used within ThemeProvider");
  return context;
};

export const useUser = () => {
  const context = useContext(UserContext);
  if (!context) throw new Error("useUser must be used within UserProvider");
  return context;
};

export const useNavigation = () => {
  const context = useContext(NavigationContext);
  if (!context) throw new Error("useNavigation must be used within NavigationProvider");
  return context;
};

export const usePond = () => {
  const context = useContext(PondContext);
  if (!context) throw new Error("usePond must be used within PondProvider");
  return context;
};

const App: React.FC = () => {
  const [showSplash, setShowSplash] = useState(true);
  const [user, setUser] = useState<UserData | null>(null);
  const [isLanguageSelected, setIsLanguageSelected] = useState(false);
  const [showTutorial, setShowTutorial] = useState(false);
  const [currentScreen, setCurrentScreen] = useState<Screen>(Screen.DASHBOARD);
  const [lang, setLang] = useState<Language>(Language.ENGLISH);
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    return (localStorage.getItem('finguard-theme') as 'light' | 'dark') || 'light';
  });

  const [pond, setPond] = useState<PondConfig>({
    id: 'POND-ALPHA-01',
    name: 'Pond Alpha',
    tankSize: '5,000 Liters',
    fishCount: 1200,
    fishType: 'Rohu & Catla',
    metrics: {
      temp: 28.5,
      ph: 7.8,
      oxygen: 6.2,
      ammonia: 0.02
    },
    healthScore: 84
  });

  useEffect(() => {
    localStorage.setItem('finguard-theme', theme);
  }, [theme]);

  const t = (key: string) => {
    return TRANSLATIONS[lang]?.[key] || TRANSLATIONS.en[key] || key;
  };

  const toggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

  const handleLanguageSelect = (selectedLang: Language) => {
    setLang(selectedLang);
    setIsLanguageSelected(true);
  };

  const renderScreen = () => {
    switch (currentScreen) {
      case Screen.DASHBOARD: return <Dashboard />;
      case Screen.DISEASE: return <DiseaseDetection />;
      case Screen.MARKETPLACE: return <Marketplace />;
      case Screen.COLD_STORAGE: return <ColdStorageScreen />;
      case Screen.ANALYTICS: return <Analytics />;
      case Screen.PROFILE: return <Profile />;
      case Screen.SCHEMES: return <Schemes />;
      default: return <Dashboard />;
    }
  };

  if (showSplash) {
    return <SplashScreen onComplete={() => setShowSplash(false)} />;
  }

  if (!isLanguageSelected) {
    return (
      <LanguageContext.Provider value={{ lang, setLang, t }}>
        <LanguageSelection onSelect={handleLanguageSelect} />
      </LanguageContext.Provider>
    );
  }

  if (!user) {
    return (
      <LanguageContext.Provider value={{ lang, setLang, t }}>
        <UserContext.Provider value={{ user, setUser }}>
          <Login onLogin={() => setShowTutorial(true)} />
        </UserContext.Provider>
      </LanguageContext.Provider>
    );
  }

  return (
    <UserContext.Provider value={{ user, setUser }}>
      <ThemeContext.Provider value={{ theme, toggleTheme }}>
        <LanguageContext.Provider value={{ lang, setLang, t }}>
          <NavigationContext.Provider value={{ currentScreen, navigate: setCurrentScreen }}>
            <PondContext.Provider value={{ pond, setPond }}>
              <div 
                className={`min-h-screen max-w-lg mx-auto flex flex-col relative animate-in fade-in duration-1000 shadow-2xl transition-colors duration-500 ${theme === 'dark' ? 'bg-[#020617] dark' : 'bg-[#f0f4f8]'}`}
                style={{ color: theme === 'dark' ? '#F1F5F9' : COLORS.darkText }}
              >
                <main className="flex-1 overflow-y-auto overflow-x-hidden no-scrollbar">
                  {renderScreen()}
                </main>

                {showTutorial && <TutorialOverlay onComplete={() => setShowTutorial(false)} />}

                <AIAssistant />

                <BottomNav 
                  currentScreen={currentScreen} 
                  onScreenChange={setCurrentScreen} 
                />
              </div>
            </PondContext.Provider>
          </NavigationContext.Provider>
        </LanguageContext.Provider>
      </ThemeContext.Provider>
    </UserContext.Provider>
  );
};

export default App;

import React from 'react';
import { Screen } from '../types';
import { NAV_ITEMS } from '../constants';
import { useLanguage } from '../App';

interface BottomNavProps {
  currentScreen: Screen;
  onScreenChange: (screen: Screen) => void;
}

const BottomNav: React.FC<BottomNavProps> = ({ currentScreen, onScreenChange }) => {
  const { t } = useLanguage();

  const getLocalizedLabel = (id: Screen) => {
    switch (id) {
      case Screen.DASHBOARD: return t('home');
      case Screen.MARKETPLACE: return t('market');
      case Screen.DISEASE: return t('detect');
      case Screen.COLD_STORAGE: return t('storage');
      case Screen.SCHEMES: return t('schemes');
      case Screen.PROFILE: return t('profile');
      default: return "";
    }
  };

  return (
    <div className="fixed bottom-6 left-5 right-5 z-[60]">
      <nav className="bg-slate-900/95 backdrop-blur-lg border border-white/10 shadow-[0_20px_50px_rgba(0,0,0,0.3)] rounded-[2rem] px-4 py-2">
        <div className="flex justify-around items-center h-16">
          {NAV_ITEMS.map((item) => {
            const isActive = currentScreen === item.id;
            return (
              <button
                key={item.id}
                onClick={() => onScreenChange(item.id)}
                className={`flex flex-col items-center justify-center flex-1 h-full transition-all duration-300 relative ${
                  isActive ? 'text-white' : 'text-slate-500 hover:text-slate-400'
                }`}
              >
                {isActive && (
                  <div className="absolute -top-1 w-8 h-1 bg-blue-500 rounded-full shadow-[0_0_10px_#3B82F6]"></div>
                )}
                <div className={`transition-transform duration-300 ${isActive ? 'scale-110 -translate-y-1' : ''}`}>
                  {React.cloneElement(item.icon as React.ReactElement<any>, { 
                    size: 22, 
                    strokeWidth: isActive ? 2.5 : 2 
                  })}
                </div>
                <span className={`text-[9px] mt-1.5 font-black uppercase tracking-widest transition-opacity duration-300 ${isActive ? 'opacity-100' : 'opacity-0 h-0 overflow-hidden'}`}>
                  {getLocalizedLabel(item.id)}
                </span>
              </button>
            );
          })}
        </div>
      </nav>
    </div>
  );
};

export default BottomNav;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Bell, Thermometer, Wind, AlertTriangle, ShieldCheck, 
  X, Check, Activity, Send, Smartphone, Loader2, CloudSun, Sun, Gauge, MapPin, Sparkles, MessageSquare, Zap, Flame, Droplet, ExternalLink, Settings2, RefreshCcw, History, Landmark, ArrowRight
} from 'lucide-react';
import { useLanguage, useTheme, usePond, useUser, useNavigation } from '../App';
import { Screen } from '../types';
import { notificationService } from '../services/notificationService';
import { getHighAccuracyLocation } from '../services/locationService';
import { fetchWeatherByCoords, WeatherData } from '../services/weatherService';
import { getWaterQualityCrisisAdvice, SearchProductResult } from '../services/geminiService';
import { draftPondReportSMS, broadcastSMS, triggerNativeSMS } from '../services/smsService';

const THRESHOLDS = {
  temp: { min: 18, max: 32 },
  oxygen: { min: 4.0, max: 12 },
  ph: { min: 6.5, max: 8.8 },
  ammonia: { min: 0, max: 0.08 }
};

interface AlertLog {
  timestamp: string;
  parameter: string;
  value: number;
  type: 'CRITICAL' | 'WARNING';
}

const Dashboard: React.FC = () => {
  const { lang } = useLanguage();
  const { theme } = useTheme();
  const { pond, setPond } = usePond();
  const { user } = useUser();
  const { navigate } = useNavigation();

  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncError, setSyncError] = useState<string | null>(null);

  const [isGettingAdvice, setIsGettingAdvice] = useState(false);
  const [crisisAdvice, setCrisisAdvice] = useState<string | null>(null);
  const [crisisProducts, setCrisisProducts] = useState<SearchProductResult[]>([]);

  const [isSmsModalOpen, setIsSmsModalOpen] = useState(false);
  const [isDrafting, setIsDrafting] = useState(false);
  const [smsDraft, setSmsDraft] = useState('');
  const [isSendingSms, setIsSendingSms] = useState(false);
  const [smsSuccess, setSmsSuccess] = useState(false);
  const [isAlarmActive, setIsAlarmActive] = useState(false);
  const [lastNotifiedTime, setLastNotifiedTime] = useState(0);

  const [alertHistory, setAlertHistory] = useState<AlertLog[]>([]);
  const [isAlertsHistoryOpen, setIsAlertsHistoryOpen] = useState(false);
  const [isFeedingActive, setIsFeedingActive] = useState(false);
  const [showFeedSuccess, setShowFeedSuccess] = useState(false);
  const [showSimPanel, setShowSimPanel] = useState(false);

  const breaches = useMemo(() => ({
    temp: pond.metrics.temp < THRESHOLDS.temp.min || pond.metrics.temp > THRESHOLDS.temp.max,
    oxygen: pond.metrics.oxygen < THRESHOLDS.oxygen.min,
    ph: pond.metrics.ph < THRESHOLDS.ph.min || pond.metrics.ph > THRESHOLDS.ph.max,
    ammonia: pond.metrics.ammonia > THRESHOLDS.ammonia.max
  }), [pond.metrics]);

  const hasAnyBreach = Object.values(breaches).some(b => b);

  useEffect(() => { handleSync(); }, []);

  useEffect(() => {
    if (hasAnyBreach) {
      Object.entries(breaches).forEach(([key, breached]) => {
        if (breached) {
          const paramName = key.charAt(0).toUpperCase() + key.slice(1);
          const val = (pond.metrics as any)[key];
          setAlertHistory(prev => {
            const lastAlert = prev[0];
            if (lastAlert && lastAlert.parameter === paramName && Math.abs(lastAlert.value - val) < 0.1) return prev;
            const newEntry: AlertLog = {
              timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
              parameter: paramName, value: val, type: 'CRITICAL'
            };
            return [newEntry, ...prev].slice(0, 10);
          });
        }
      });

      if (!isAlarmActive) {
        setIsAlarmActive(true);
        const now = Date.now();
        if (now - lastNotifiedTime > 180000) { // Notify every 3 mins during crisis
          handleEmergencyProtocol();
          setLastNotifiedTime(now);
        }
      }
    } else {
      setIsAlarmActive(false);
    }
  }, [hasAnyBreach, pond.metrics]);

  const handleEmergencyProtocol = async () => {
    const title = "CRITICAL POND BREACH";
    const body = `Alert: ${pond.name} parameters unsafe. Oxygen: ${pond.metrics.oxygen}mg/L. Check FinGuard App.`;

    await notificationService.notifyCrisis(title, body, {
      phone: user?.phone,
      email: user?.email || `${user?.name?.toLowerCase().replace(/\s+/g, '.')}@farm.ai`
    });
  };

  const handleSync = async () => {
    setIsSyncing(true);
    try {
      const loc = await getHighAccuracyLocation();
      const weatherData = await fetchWeatherByCoords(loc.lat, loc.lng);
      setWeather(weatherData);
    } catch (err) { setSyncError("Sync failed"); }
    finally { setIsSyncing(false); }
  };

  const handleQuickFeed = () => {
    setIsFeedingActive(true);
    setTimeout(() => {
      setIsFeedingActive(false);
      setShowFeedSuccess(true);
      setPond(prev => ({ ...prev, healthScore: Math.min(100, prev.healthScore + 2) }));
      setTimeout(() => setShowFeedSuccess(false), 3000);
    }, 2000);
  };

  const handleOpenSmsModal = async () => {
    setIsSmsModalOpen(true);
    setIsDrafting(true);
    try {
      const draft = await draftPondReportSMS(pond.name, {
        temp: pond.metrics.temp.toString(),
        ph: pond.metrics.ph.toString(),
        oxygen: pond.metrics.oxygen.toString(),
        ammonia: pond.metrics.ammonia.toString()
      }, pond.healthScore, lang);
      setSmsDraft(draft);
    } catch { setSmsDraft("FinGuard: Pond health status updated."); }
    finally { setIsDrafting(false); }
  };

  const health = useMemo(() => {
    const score = pond.healthScore;
    if (hasAnyBreach) return { 
      label: 'BREACH DETECTED', icon: <Flame className="animate-pulse" size={24} />,
      gradient: 'from-rose-950 via-rose-600 to-rose-950'
    };
    if (score < 40) return { 
      label: 'DANGER ZONE', icon: <AlertTriangle className="animate-bounce" size={24} />,
      gradient: 'from-red-900 via-red-600 to-red-900'
    };
    return { 
      label: 'EXCELLENT', icon: <ShieldCheck size={24} />,
      gradient: 'from-emerald-600 via-teal-500 to-emerald-600'
    };
  }, [pond.healthScore, hasAnyBreach]);

  return (
    <div className={`pb-48 relative min-h-screen transition-all duration-700 ${theme === 'dark' ? 'bg-[#020617]' : 'bg-[#f0f4f8]'}`}>
      <div className={`fixed top-0 left-0 right-0 h-96 opacity-20 blur-[120px] pointer-events-none transition-all duration-1000 bg-gradient-to-b ${health.gradient}`}></div>

      {isAlarmActive && (
        <div className="fixed top-0 left-0 right-0 z-[100] bg-rose-600 text-white px-6 py-4 flex items-center justify-between shadow-2xl animate-in slide-in-from-top duration-500">
           <div className="flex items-center space-x-3">
              <div className="p-2 bg-white/20 rounded-xl animate-pulse"><AlertTriangle size={20} /></div>
              <div className="flex flex-col">
                 <span className="text-[10px] font-black uppercase tracking-widest leading-none mb-1 text-rose-200">Critical Failure</span>
                 <span className="text-sm font-black tracking-tight">System Alarm Active</span>
              </div>
           </div>
           <div className="flex items-center space-x-2">
              <div className="flex items-center space-x-1 bg-white/10 px-3 py-1.5 rounded-full border border-white/10">
                 <Smartphone size={12} className="text-rose-200" />
                 <span className="text-[9px] font-black uppercase tracking-widest">MULTI-CHANNEL ALERT</span>
              </div>
           </div>
        </div>
      )}

      <div className={`safe-area-top sticky top-0 z-50 bg-white/70 dark:bg-slate-900/70 backdrop-blur-xl border-b transition-transform ${isAlarmActive ? 'translate-y-16' : ''}`}>
        <div className="flex justify-between items-center px-6 h-24">
          <div className="flex items-center space-x-4">
            <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-white shadow-xl bg-gradient-to-br ${health.gradient}`}>
              <Smartphone size={24} />
            </div>
            <div>
              <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 mb-0.5">Farm Arjun,</p>
              <h2 className="text-lg font-black dark:text-white leading-none">Pond Security Active</h2>
            </div>
          </div>
          <button onClick={handleSync} className="w-12 h-12 flex items-center justify-center rounded-2xl bg-white dark:bg-slate-800 shadow-lg text-blue-600">
            {isSyncing ? <Loader2 size={20} className="animate-spin" /> : <MapPin size={20} />}
          </button>
        </div>
      </div>

      <div className="px-6 py-8 space-y-8">
        {/* Health Gauge */}
        <div className={`relative overflow-hidden rounded-[3rem] p-10 text-white shadow-2xl transition-all duration-700 bg-gradient-to-br ${health.gradient}`}>
          <div className="relative z-10 flex flex-col items-center">
            <div className="w-full flex justify-between items-start mb-6">
              <p className="text-[11px] font-black uppercase tracking-[0.3em] opacity-60">Pond Health Index</p>
              <div className="px-4 py-1.5 rounded-full border border-white/20 backdrop-blur-md font-black text-[10px] uppercase tracking-widest bg-white/10 flex items-center space-x-2">
                {health.icon} <span>{health.label}</span>
              </div>
            </div>
            <h1 className="text-9xl font-black tracking-tighter drop-shadow-2xl">{hasAnyBreach ? '!!' : pond.healthScore}</h1>
            <div className="w-full bg-black/10 rounded-full h-4 p-1 backdrop-blur-sm mt-4">
              <div className="h-full bg-white rounded-full transition-all duration-1000 ease-out" style={{ width: `${hasAnyBreach ? 100 : pond.healthScore}%` }}></div>
            </div>
          </div>
        </div>

        {/* Government Schemes Spotlight */}
        <button 
          onClick={() => navigate(Screen.SCHEMES)}
          className={`w-full p-6 rounded-[2.5rem] border flex items-center justify-between transition-all active:scale-[0.98] relative overflow-hidden group ${
            theme === 'dark' ? 'bg-emerald-500/5 border-emerald-500/10' : 'bg-emerald-50 border-emerald-100'
          }`}
        >
          <div className="flex items-center space-x-4 relative z-10">
            <div className="w-12 h-12 bg-emerald-500 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-emerald-500/20">
              <Landmark size={24} />
            </div>
            <div className="text-left">
              <p className="text-[9px] font-black uppercase tracking-widest text-emerald-600 dark:text-emerald-400 mb-0.5">Government Schemes</p>
              <h3 className={`text-sm font-black tracking-tight ${theme === 'dark' ? 'text-white' : 'text-slate-800'}`}>Unlock Subsidies Now</h3>
            </div>
          </div>
          <ArrowRight size={20} className="text-emerald-500 relative z-10 group-hover:translate-x-1 transition-transform" />
          <div className="absolute right-0 top-0 bottom-0 w-32 bg-gradient-to-l from-emerald-500/5 to-transparent pointer-events-none"></div>
        </button>

        {/* Metrics Grid */}
        <div className="grid grid-cols-2 gap-6">
          {[
            { label: 'TEMP', value: pond.metrics.temp, icon: <Thermometer />, breached: breaches.temp, color: 'bg-orange-500' },
            { label: 'OXYGEN', value: pond.metrics.oxygen, icon: <Wind />, breached: breaches.oxygen, color: 'bg-blue-500' },
            { label: 'PH', value: pond.metrics.ph, icon: <Droplet />, breached: breaches.ph, color: 'bg-emerald-500' },
            { label: 'AMMONIA', value: pond.metrics.ammonia, icon: <Activity />, breached: breaches.ammonia, color: 'bg-purple-500' },
          ].map((m, i) => (
            <div key={i} className={`p-8 rounded-[3.5rem] shadow-sm flex flex-col items-center space-y-4 border transition-all ${m.breached ? 'animate-pulse border-rose-500 bg-rose-50/10' : (theme === 'dark' ? 'bg-slate-900 border-white/5' : 'bg-white border-slate-50')}`}>
              <div className={`w-16 h-16 rounded-[1.5rem] flex items-center justify-center ${theme === 'dark' ? 'bg-white/5' : 'bg-slate-50'}`}>
                {React.cloneElement(m.icon as React.ReactElement<any>, { className: m.breached ? 'text-rose-600' : 'text-blue-600', size: 28 })}
              </div>
              <div className="text-center">
                <p className={`text-[9px] font-black uppercase tracking-widest ${m.breached ? 'text-rose-400' : 'text-slate-400'}`}>{m.label}</p>
                <p className={`text-3xl font-black ${m.breached ? 'text-rose-600' : (theme === 'dark' ? 'text-white' : 'text-slate-900')}`}>{m.value}</p>
              </div>
              <div className={`w-12 h-1.5 rounded-full ${m.breached ? 'bg-rose-600' : m.color}`}></div>
            </div>
          ))}
        </div>

        {/* Quick Actions */}
        <div className="grid grid-cols-4 gap-4">
          {[
            { label: 'Feed', icon: <Droplet />, color: 'bg-blue-500', onClick: handleQuickFeed },
            { label: 'Alerts', icon: <Bell />, color: 'bg-orange-500', onClick: () => setIsAlertsHistoryOpen(true) },
            { label: 'Broadcast', icon: <Send />, color: 'bg-indigo-600', onClick: handleOpenSmsModal },
            { label: 'Console', icon: <Settings2 />, color: 'bg-slate-600', onClick: () => setShowSimPanel(true) },
          ].map((action, i) => (
            <button key={i} onClick={action.onClick} className="flex flex-col items-center space-y-2 group active:scale-90 transition-all">
              <div className={`${action.color} w-16 h-16 rounded-full flex items-center justify-center text-white shadow-xl group-hover:-translate-y-1 transition-transform`}>
                {React.cloneElement(action.icon as React.ReactElement<any>, { size: 24 })}
              </div>
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{action.label}</span>
            </button>
          ))}
        </div>
      </div>

      {/* Simulation Console */}
      {showSimPanel && (
        <div className="fixed inset-0 z-[120] flex items-end justify-center animate-in fade-in duration-300">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md" onClick={() => setShowSimPanel(false)} />
          <div className={`w-full max-w-sm rounded-t-[3rem] p-8 shadow-2xl relative border-t ${theme === 'dark' ? 'bg-slate-900 border-white/10' : 'bg-white border-slate-100'}`}>
            <div className="flex justify-between items-center mb-8">
              <h3 className={`text-sm font-black uppercase tracking-widest ${theme === 'dark' ? 'text-white' : 'text-slate-800'}`}>Sensor Override</h3>
              <button onClick={() => setShowSimPanel(false)}><X size={24} className="text-slate-400" /></button>
            </div>
            <div className="space-y-6">
              {Object.keys(pond.metrics).map((key) => (
                <div key={key} className="space-y-2">
                  <div className="flex justify-between text-[10px] font-black uppercase text-slate-400">
                    <span>{key}</span>
                    <span className="text-blue-500">{(pond.metrics as any)[key]}</span>
                  </div>
                  <input 
                    type="range" min="0" max="40" step="0.1" 
                    value={(pond.metrics as any)[key]} 
                    onChange={(e) => setPond(p => ({ ...p, metrics: { ...p.metrics, [key]: parseFloat(e.target.value) } }))}
                    className="w-full accent-blue-600"
                  />
                </div>
              ))}
              <div className="pt-4 flex space-x-3">
                <button onClick={() => setPond(p => ({ ...p, metrics: { temp: 28, ph: 7.5, oxygen: 6.5, ammonia: 0.01 } }))} className="flex-1 bg-slate-100 dark:bg-slate-800 p-4 rounded-2xl text-[10px] font-black uppercase">Reset</button>
                <button onClick={() => setPond(p => ({ ...p, metrics: { ...p.metrics, oxygen: 1.5 } }))} className="flex-1 bg-rose-600 text-white p-4 rounded-2xl text-[10px] font-black uppercase shadow-lg shadow-rose-500/30">Trigger Crisis</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;
